"use client"

import React from "react"
import PostCard, {PostCardProps} from "./PostCard"
import router from "next/router"

interface RecentPostsProps {
  posts: PostCardProps[]
  onLoadMore?: () => void
  hasMore?: boolean
}

export default function RecentPosts({
  posts,
  onLoadMore,
  hasMore = false,
}: RecentPostsProps) {
  return (
    <main className="bg-slate-900 min-h-screen text-white pt-8 pb-16">
      <section className="max-w-7xl mx-auto px-4 md:px-8">
        {/* Header Section */}
        <h1 className="text-3xl md:text-4xl font-bold mb-2">📰 Recent Posts</h1>
        <p className="text-slate-400 mb-6 text-sm md:text-base">
          Catch up on what the community is talking about. Scroll through the latest
          submissions!
        </p>

        {/* Posts Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {posts.map((post) => (
            <PostCard
              key={post.id}
              {...post}
              onClick={(postId) => router.push(`/posts/${postId}`)}
            />
          ))}
        </div>

        {/* Load More Button */}
        {hasMore && (
          <div className="flex justify-center mt-10">
            <button
              onClick={onLoadMore}
              className="bg-slate-700 hover:bg-slate-600 text-white rounded-xl py-2 px-6 font-medium transition"
            >
              Load More
            </button>
          </div>
        )}
      </section>
    </main>
  )
}
